using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator;

    public ScoreCalculatorTests()
    {
        _calculator = new ScoreCalculator();
    }

    // ── CalculatePercentage ─────────────────────────────────────────

    [TestMethod]
    [DataRow(10, 10, 100.0, DisplayName = "Perfect score")]
    [DataRow(0, 10, 0.0, DisplayName = "Zero correct")]
    [DataRow(5, 10, 50.0, DisplayName = "Half correct")]
    [DataRow(1, 3, 33.333333333333336, DisplayName = "Repeating decimal")]
    [DataRow(1, 1, 100.0, DisplayName = "Single question perfect")]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(
        int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_ResultAlwaysInRange()
    {
        // Any valid input must produce a result in [0, 100]
        var result = _calculator.CalculatePercentage(7, 10);

        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void CalculatePercentage_PerfectScore_ReturnsExactly100()
    {
        var result = _calculator.CalculatePercentage(10, 10);

        Assert.IsGreaterThan(99.99, result); // not just "close to" 100
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));

        Assert.AreEqual("total", ex.ParamName);
    }

    [TestMethod]
    public void CalculatePercentage_NegativeTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, -1));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));

        Assert.AreEqual("correct", ex.ParamName);
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    // ── GetGrade boundary tests ─────────────────────────────────────

    [TestMethod]
    [DataRow(100.0, "A", DisplayName = "100 → A")]
    [DataRow(90.0, "A", DisplayName = "90 (boundary) → A")]
    [DataRow(89.99, "B", DisplayName = "89.99 (just below A) → B")]
    [DataRow(80.0, "B", DisplayName = "80 (boundary) → B")]
    [DataRow(79.99, "C", DisplayName = "79.99 (just below B) → C")]
    [DataRow(70.0, "C", DisplayName = "70 (boundary) → C")]
    [DataRow(69.99, "D", DisplayName = "69.99 (just below C) → D")]
    [DataRow(60.0, "D", DisplayName = "60 (boundary) → D")]
    [DataRow(59.99, "F", DisplayName = "59.99 (just below D) → F")]
    [DataRow(0.0, "F", DisplayName = "0 → F")]
    public void GetGrade_BoundaryValues_ReturnsCorrectGrade(
        double percentage, string expectedGrade)
    {
        var grade = _calculator.GetGrade(percentage);

        Assert.AreEqual(expectedGrade, grade);
    }

    [TestMethod]
    public void GetGrade_NegativePercentage_ReturnsF()
    {
        // Negative values aren't rejected, so they should fall to default
        var grade = _calculator.GetGrade(-5.0);

        Assert.AreEqual("F", grade);
    }

    [TestMethod]
    public void GetGrade_AboveHundred_ReturnsA()
    {
        var grade = _calculator.GetGrade(105.0);

        Assert.AreEqual("A", grade);
    }

    // ── NormalizeScore ───────────────────────────────────────────────

    [TestMethod]
    [DataRow(50.0, 100.0, 50.0, DisplayName = "Half of max")]
    [DataRow(0.0, 100.0, 0.0, DisplayName = "Zero raw score")]
    [DataRow(100.0, 100.0, 100.0, DisplayName = "Exact max")]
    [DataRow(75.0, 150.0, 50.0, DisplayName = "Different scale")]
    public void NormalizeScore_ValidInputs_ReturnsExpected(
        double rawScore, double maxRaw, double expected)
    {
        var result = _calculator.NormalizeScore(rawScore, maxRaw);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void NormalizeScore_ResultNeverExceeds100()
    {
        // Raw score exceeds max — should be capped at 100
        var result = _calculator.NormalizeScore(150.0, 100.0);

        Assert.IsLessThan(100.01, result);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ResultAlwaysNonNegative()
    {
        var result = _calculator.NormalizeScore(0.0, 50.0);

        Assert.IsGreaterThan(-0.01, result);
        Assert.AreEqual(0.0, result);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRawScore_Throws()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1.0, 100.0));

        Assert.AreEqual("rawScore", ex.ParamName);
    }

    [TestMethod]
    public void NormalizeScore_ZeroMaxRaw_Throws()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50.0, 0.0));

        Assert.AreEqual("maxRaw", ex.ParamName);
    }

    [TestMethod]
    public void NormalizeScore_NegativeMaxRaw_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50.0, -10.0));
    }
}

